const fruits = ["تفاح", "موز", "عنب", "مانجو"];
console.log(fruits[0]);              // تفاح
console.log(fruits.length);          // 4
console.log(fruits[fruits.length - 1]); // مانجو (الأخير)

fruits[1] = "فراولة";              // تعديل عنصر
console.log(fruits);

const nums = [10, 20, 30, 40, 50];

const part = nums.slice(1, 4);
console.log(part);  // [20, 30, 40]
console.log(nums);  // الأصل سليم

nums.splice(2, 1, 99, 88); // من الفهرس 2: احذف 1 وأضف 99 و88
console.log(nums);  // [10, 20, 99, 88, 40, 50]

const nums = [40, 5, 100, 23];

console.log(nums.includes(100));  // true
console.log(nums.indexOf(23));    // 3

nums.sort((a, b) => a - b);
console.log(nums);                 // [5, 23, 40, 100]

console.log(nums.join(" - "));  // "5 - 23 - 40 - 100"
